import{_ as a,o as r,c as d,ag as e}from"./chunks/framework.CQYuu_FX.js";const b=JSON.parse('{"title":"レポート","description":"","frontmatter":{"title":"レポート"},"headers":[],"relativePath":"tenant/13-reports.md","filePath":"tenant/13-reports.md"}'),o={name:"tenant/13-reports.md"};function l(i,t,n,s,h,c){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="_13-レポート" tabindex="-1">13. レポート <a class="header-anchor" href="#_13-レポート" aria-label="Permalink to &quot;13. レポート&quot;">​</a></h1><p>レポートでは、売上、会計、商品、客席、スタッフ、在庫、予約などの状況を確認できます。日々の振り返りと経営判断に活用してください。</p><h2 id="主なレポート" tabindex="-1">主なレポート <a class="header-anchor" href="#主なレポート" aria-label="Permalink to &quot;主なレポート&quot;">​</a></h2><table tabindex="0"><thead><tr><th>レポート</th><th>確認できること</th></tr></thead><tbody><tr><td><strong>週次サマリー</strong></td><td>売上レポートの最上部にある、直近1週間の売上・客数・客単価・人気商品の概要。</td></tr><tr><td>売上レポート</td><td>日別、期間別、支払い方法別の売上</td></tr><tr><td>レジレポート</td><td>現金、入金、出金、差額</td></tr><tr><td>商品レポート</td><td>売れ筋、ABC分析、併売傾向</td></tr><tr><td>客席レポート</td><td>回転率、滞在時間、テーブル別傾向</td></tr><tr><td>スタッフレポート</td><td>勤怠、操作履歴、担当別の実績</td></tr><tr><td>満足度分析</td><td>評価件数、平均評価、低評価の理由・品目・時間帯</td></tr><tr><td>予約レポート</td><td>予約件数、来店数、キャンセル傾向</td></tr></tbody></table><h2 id="満足度分析" tabindex="-1">満足度分析 <a class="header-anchor" href="#満足度分析" aria-label="Permalink to &quot;満足度分析&quot;">​</a></h2><p>管理画面 → レポート → 満足度分析 から開きます。お客様のセルフ注文画面で送信された評価（1〜5）を集計し、店舗改善に活用できます。</p><ul><li><strong>サマリー</strong>: 評価件数、平均評価、低評価件数（1〜2）、低評価率、高評価件数（4〜5）</li><li><strong>低評価の理由ランキング</strong>: 提供が遅かった／味／温度／量／注文内容の相違／接客／清潔感／価格／その他</li><li><strong>低評価が出た品目ランキング</strong>: どの品目に低評価が集中しているか</li><li><strong>時間帯別 低評価</strong>: ピーク時に提供品質が落ちていないか確認</li><li><strong>直近の低評価一覧</strong>: 日時・品目・評価・理由・自由コメント・テーブル・注文ID</li></ul><div class="tip custom-block"><p class="custom-block-title">低評価は改善のヒントとして活用してください</p><p>低評価はスタッフ個人の責任ではなく、「品目・時間帯・店舗運営の改善点」として活用する前提で設計しています。顧客セルフ注文ではスタッフ担当者が特定されないケースも多いため、まずは品目・時間帯・オペレーションの見直しをお勧めします。</p></div><p>オーナー画面の「全店舗横断レポート」にも、全店舗合算の満足度サマリー・店舗別平均評価・低評価が多い品目・理由ランキングが表示されます。</p><h2 id="期間の選び方" tabindex="-1">期間の選び方 <a class="header-anchor" href="#期間の選び方" aria-label="Permalink to &quot;期間の選び方&quot;">​</a></h2><p>日報は営業終了後、週報は週明け、月報は月末または翌月初に確認する運用を推奨します。深夜営業の店舗では、営業日区切り時刻に注意してください。</p><h2 id="csv出力" tabindex="-1">CSV出力 <a class="header-anchor" href="#csv出力" aria-label="Permalink to &quot;CSV出力&quot;">​</a></h2><p>必要に応じてCSVを出力し、会計ソフトや表計算ソフトで集計できます。出力後は個人情報や売上情報の取り扱いに注意してください。</p><h2 id="活用例" tabindex="-1">活用例 <a class="header-anchor" href="#活用例" aria-label="Permalink to &quot;活用例&quot;">​</a></h2><ul><li>売れ筋商品を確認して仕入れ量を調整する</li><li>回転率の低い時間帯を見つけて人員配置を見直す</li><li>返金やレジ差額を確認して運用改善につなげる</li><li>スタッフ別の実績を評価や教育に活用する</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>数値が合わない</td><td>期間、営業日区切り、会計済み状態を確認してください。</td></tr><tr><td>CSVが開けない</td><td>UTF-8対応のソフトで開いてください。</td></tr><tr><td>特定店舗が出ない</td><td>店舗選択と閲覧権限を確認してください。</td></tr><tr><td>レジ差額がある</td><td>入金、出金、返金、現金残高を確認してください。</td></tr></tbody></table>',17)])])}const u=a(o,[["render",l]]);export{b as __pageData,u as default};
